# Simulate the full fix for Header.fromstring
def decode_ascii(s):
    if isinstance(s, bytes):
        return s.decode('ascii')
    return s

class Card:
    length = 80

END_CARD = 'END' + ' ' * 77
VALID_HEADER_CHARS = set(map(chr, range(0x20, 0x7F)))

def _pad(input):
    _len = len(input)
    if _len == Card.length:
        return input
    elif _len > Card.length:
        strlen = _len % Card.length
        if strlen == 0:
            return input
        else:
            return input + ' ' * (Card.length - strlen)
    else:
        strlen = _len % Card.length
        return input + ' ' * (Card.length - strlen)

def card_fromstring(image):
    if isinstance(image, bytes):
        image = decode_ascii(image)
    return _pad(image)

# Simulate Header.fromstring
def header_fromstring(data, sep=''):
    if isinstance(data, bytes):
        data = decode_ascii(data)

    cards = []
    require_full_cardlength = set(sep).issubset(VALID_HEADER_CHARS)

    idx = 0
    image = []

    while idx < len(data):
        if require_full_cardlength:
            end_idx = idx + Card.length
        else:
            try:
                end_idx = data.index(sep, idx)
            except ValueError:
                end_idx = len(data)

        next_image = data[idx:end_idx]
        idx = end_idx + len(sep)

        if image:
            if next_image[:8] == 'CONTINUE':
                image.append(next_image)
                continue
            cards.append(card_fromstring(''.join(image)))

        if require_full_cardlength:
            if next_image == END_CARD:
                image = []
                break
        else:
            if next_image.split(sep)[0].rstrip() == 'END':
                image = []
                break

        image = [next_image]

    if image:
        cards.append(card_fromstring(''.join(image)))

    return cards

# Test with bytes (a simple FITS header)
header_bytes = b'SIMPLE  =                    T / file does conform to FITS standard\nBITPIX  =                   16 / number of bits per data pixel\nEND' + b' ' * 77 + b'\n'

result = header_fromstring(header_bytes)
print(f"Header.fromstring with bytes: {len(result)} cards")
for c in result:
    print(f"  Card: {c!r}")

# Test with str
header_str = 'SIMPLE  =                    T / file does conform to FITS standard\nBITPIX  =                   16 / number of bits per data pixel\nEND' + ' ' * 77 + '\n'

result = header_fromstring(header_str)
print(f"\nHeader.fromstring with str: {len(result)} cards")
for c in result:
    print(f"  Card: {c!r}")

print("\nAll tests passed!")
EOF
"}

